function parseRange(s) {
  const hyphenIndex = s.indexOf('-');

  if (hyphenIndex === -1) {
    return [parseInt(s, 10)];
  }

  const a = parseInt(s.substring(0, hyphenIndex), 10);
  const b = parseInt(s.substring(hyphenIndex + 1), 10);

  const result = [];
  if (a <= b) {
    for (let i = a; i <= b; i++) {
      result.push(i);
    }
  } else {
    for (let i = a; i >= b; i--) {
      result.push(i);
    }
  }

  return result;
}
